// Guards against canvasMetrics() measuring the board's container before
// fonts/layout have settled (which can leave the canvas stuck at ~1px):
// re-render whenever the container's actual size changes, including the
// implicit first callback ResizeObserver fires right after observe().
const boardResizeObserver=new ResizeObserver(()=>renderBoard());boardResizeObserver.observe($('board').parentElement);
const THEME_STORAGE_KEY='hrifa-grid-traversal-theme-v1';
function applyTheme(dark){document.documentElement.setAttribute('data-theme',dark?'dark':'light');const btn=$('themeButton');if(btn){btn.setAttribute('aria-pressed',String(dark));btn.textContent=dark?'Light':'Dark'}}
function setTheme(dark){applyTheme(dark);try{localStorage.setItem(THEME_STORAGE_KEY,String(dark))}catch{}render()}
function restoreTheme(){let dark=false;try{const saved=localStorage.getItem(THEME_STORAGE_KEY);dark=saved===null?matchMedia('(prefers-color-scheme: dark)').matches:saved==='true'}catch{}applyTheme(dark)}
$('themeButton').addEventListener('click',()=>setTheme(document.documentElement.dataset.theme!=='dark'));
restoreTheme();
render();
